() => {
    const greenBinText = document.querySelector('[ref="e308"]').textContent;
    const brownBinText = document.querySelector('[ref="e309"]').textContent;
    const blueBinText = document.querySelector('[ref="e310"]').textContent;
    const orangeBinText = document.querySelector('[ref="e311"]').textContent;

    const extractInfo = (text) => {
        const dateMatch = text.match(/\: (.*?)\s*\(/);
        const frequencyMatch = text.match(/\((.*?)\)/);
        return {
            next_pickup_day: dateMatch ? dateMatch[1].trim() : null,
            frequency: frequencyMatch ? frequencyMatch[1].trim() : null
        };
    };

    return {
        greenBin: extractInfo(greenBinText),
        brownBin: extractInfo(brownBinText),
        blueBin: extractInfo(blueBinText),
        orangeBin: extractInfo(orangeBinText)
    };
}

() => {
    const results = {};

    const binTypes = {
        'General waste wheeled bin': { color: 'grey', type: 'general_waste' },
        'Brown garden waste wheeled bin': { color: 'brown', type: 'garden_waste' },
        'Blue kerbside box - paper': { color: 'blue', type: 'recycling' },
        'Green kerbside box - cans, glass and aluminium foil': { color: 'green', type: 'recycling' },
        'Plastic and cardboard wheeled bin': { color: 'blue', type: 'recycling' }
    };

    for (const [binName, binInfo] of Object.entries(binTypes)) {
        const links = Array.from(document.querySelectorAll(`a[href*="bins-boxes-and-bags/"]`)).filter(link => link.textContent.includes(binName));
        if (links.length > 0) {
            const firstLink = links[0];
            let currentElement = firstLink;
            let nextPickupDay = null;

            while (currentElement && currentElement.tagName !== 'BODY') {
                if (currentElement.tagName === 'H4') {
                    nextPickupDay = currentElement.textContent.trim();
                    break;
                }
                currentElement = currentElement.parentElement;
            }

            if (nextPickupDay) {
                // Check for asterisk indicating bank holiday
                const isBankHoliday = nextPickupDay.includes("(*)");
                if (isBankHoliday) {
                    nextPickupDay = nextPickupDay.replace("(*)", "").trim();
                }

                // Determine frequency (assuming fortnightly based on typical patterns and available data)
                const frequency = "Fortnightly";

                // Store the first found collection for each bin type
                if (!results[binInfo.type]) {
                    results[binInfo.type] = {
                        bin_colour: binInfo.color,
                        frequency: frequency,
                        next_pickup_day: nextPickupDay
                    };
                }
            }
        }
    }

    return results;
}

