() => {
    const results = {
        general_waste: null,
        garden_waste: null,
        recycling: null,
        food_waste: null
    };

    const binTypeMap = {
        'General waste wheeled bin': { color: 'grey', type: 'general_waste' },
        'Brown garden waste wheeled bin': { color: 'brown', type: 'garden_waste' },
        'Blue kerbside box - paper': { color: 'blue', type: 'recycling' },
        'Green kerbside box - cans, glass and aluminium foil': { color: 'green', type: 'recycling' },
        'Plastic and cardboard wheeled bin': { color: 'blue', type: 'recycling' }
    };

    const dateHeadings = document.querySelectorAll('h4');

    dateHeadings.forEach(heading => {
        const nextPickupDay = heading.textContent.trim().replace('(*)', '').trim();
        let currentElement = heading.nextElementSibling;

        while (currentElement && currentElement.tagName !== 'H4') {
            if (currentElement.tagName === 'UL') {
                const listItems = currentElement.querySelectorAll('li');
                listItems.forEach(item => {
                    const binText = item.querySelector('a')?.textContent.trim();
                    if (binText) {
                        for (const [key, value] of Object.entries(binTypeMap)) {
                            if (binText.includes(key) && !results[value.type]) {
                                results[value.type] = {
                                    bin_colour: value.color,
                                    frequency: 'Fortnightly',
                                    next_pickup_day: nextPickupDay
                                };
                            }
                        }
                    }
                });
            }
            currentElement = currentElement.nextElementSibling;
        }
    });

    return results;
}

